+/** Mirrors getQueryStores so relation-pair modifier values read their target store. */
+function getQueryPairInputs(params: QueryParameter[]): (RelationPair | undefined)[] {
+    const pairs: (RelationPair | undefined)[] = [];
+    for (const param of params) {
+        if (isRelationPair(param)) {
+            if (param[$internal].relation[$internal].trait[$internal].type !== 'tag') pairs.push(param);
+        } else if (isModifier(param)) {
+            if (param.type === 'not') continue;
+            const modifierPairs = param.pairs ?? [];
+            for (const trait of param.traits) {
+                if (trait[$internal].type === 'tag') continue;
+                pairs.push(modifierPairs.find((pair) => pair[$internal].relation[$internal].trait === trait));
+            }
+        } else if ((param as Trait)[$internal].type !== 'tag') {
+            pairs.push(undefined);
